SELECT "STORE"."S_STORE_NAME", "STORE"."S_COMPANY_ID", "STORE"."S_STREET_NUMBER", "STORE"."S_STREET_NAME", "STORE"."S_STREET_TYPE", "STORE"."S_SUITE_NUMBER", "STORE"."S_CITY", "STORE"."S_COUNTY", "STORE"."S_STATE", "STORE"."S_ZIP", SUM(CASE WHEN "STORE_RETURNS"."SR_RETURNED_DATE_SK" - "STORE_SALES"."SS_SOLD_DATE_SK" <= 30 THEN 1 ELSE 0 END) AS "30 days", SUM(CASE WHEN "STORE_RETURNS"."SR_RETURNED_DATE_SK" - "STORE_SALES"."SS_SOLD_DATE_SK" > 30 AND "STORE_RETURNS"."SR_RETURNED_DATE_SK" - "STORE_SALES"."SS_SOLD_DATE_SK" <= 60 THEN 1 ELSE 0 END) AS "31-60 days", SUM(CASE WHEN "STORE_RETURNS"."SR_RETURNED_DATE_SK" - "STORE_SALES"."SS_SOLD_DATE_SK" > 60 AND "STORE_RETURNS"."SR_RETURNED_DATE_SK" - "STORE_SALES"."SS_SOLD_DATE_SK" <= 90 THEN 1 ELSE 0 END) AS "61-90 days", SUM(CASE WHEN "STORE_RETURNS"."SR_RETURNED_DATE_SK" - "STORE_SALES"."SS_SOLD_DATE_SK" > 90 AND "STORE_RETURNS"."SR_RETURNED_DATE_SK" - "STORE_SALES"."SS_SOLD_DATE_SK" <= 120 THEN 1 ELSE 0 END) AS "91-120 days", SUM(CASE WHEN "STORE_RETURNS"."SR_RETURNED_DATE_SK" - "STORE_SALES"."SS_SOLD_DATE_SK" > 120 THEN 1 ELSE 0 END) AS ">120 days"
FROM "tpcds"."STORE_SALES",
"tpcds"."STORE_RETURNS",
"tpcds"."STORE",
"tpcds"."DATE_DIM",
"tpcds"."DATE_DIM" AS "DATE_DIM0"
WHERE "DATE_DIM0"."D_YEAR" = 1998 AND "DATE_DIM0"."D_MOY" = 9 AND ("STORE_SALES"."SS_TICKET_NUMBER" = "STORE_RETURNS"."SR_TICKET_NUMBER" AND "STORE_SALES"."SS_ITEM_SK" = "STORE_RETURNS"."SR_ITEM_SK") AND ("STORE_SALES"."SS_SOLD_DATE_SK" = "DATE_DIM"."D_DATE_SK" AND "STORE_RETURNS"."SR_RETURNED_DATE_SK" = "DATE_DIM0"."D_DATE_SK" AND ("STORE_SALES"."SS_CUSTOMER_SK" = "STORE_RETURNS"."SR_CUSTOMER_SK" AND "STORE_SALES"."SS_STORE_SK" = "STORE"."S_STORE_SK"))
GROUP BY "STORE"."S_STORE_NAME", "STORE"."S_COMPANY_ID", "STORE"."S_STREET_NUMBER", "STORE"."S_STREET_NAME", "STORE"."S_STREET_TYPE", "STORE"."S_SUITE_NUMBER", "STORE"."S_CITY", "STORE"."S_COUNTY", "STORE"."S_STATE", "STORE"."S_ZIP"
ORDER BY "STORE"."S_STORE_NAME", "STORE"."S_COMPANY_ID", "STORE"."S_STREET_NUMBER", "STORE"."S_STREET_NAME", "STORE"."S_STREET_TYPE", "STORE"."S_SUITE_NUMBER", "STORE"."S_CITY", "STORE"."S_COUNTY", "STORE"."S_STATE", "STORE"."S_ZIP"
FETCH NEXT 100 ROWS ONLY
